import os, sys, django, ast, inspect, textwrap
os.environ.setdefault("DJANGO_SETTINGS_MODULE", "sentry.conf.server")
sys.path.insert(0, os.path.join(os.getcwd(), "src"))
# Avoid starting the full server; just run django.setup()
django.setup()
from django.db import models as django_models
from sentry.db.models import FlexibleForeignKey
from sentry.models.group import Group

results = []
for model in django.apps.apps.get_models():
    if model is Group:
        continue
    for field in model._meta.get_fields():
        if isinstance(field, (django_models.ForeignKey, FlexibleForeignKey, django_models.OneToOneField, django_models.ManyToManyField)):
            if field.related_model is Group:
                results.append((model, field))

# Sort by file and field name

def locate_field_line(model, field_name):
    try:
        srcfile = inspect.getsourcefile(model)
        source, start_lineno = inspect.getsourcelines(model)
        # parse the class body to find assignment to field_name
        tree = ast.parse(textwrap.dedent("".join(source)))
        cls = tree.body[0]
        for node in cls.body:
            if isinstance(node, ast.Assign):
                for target in node.targets:
                    if isinstance(target, ast.Name) and target.id == field_name:
                        return srcfile, start_lineno + node.lineno - 1
            elif isinstance(node, ast.AnnAssign):
                if isinstance(node.target, ast.Name) and node.target.id == field_name:
                    return srcfile, start_lineno + node.lineno - 1
    except Exception as e:
        return None, 0
    return None, 0

for model, field in sorted(results, key=lambda x: x[0].__name__):
    srcfile, lineno = locate_field_line(model, field.name)
    if srcfile:
        print(f"{srcfile}:{lineno}\t{model.__name__}.{field.name}")
