import ast, os, sys
from pathlib import Path

ROOT = Path("src/sentry")
TARGET_NAMES = {"FlexibleForeignKey", "ForeignKey", "OneToOneField", "ManyToManyField", "HybridCloudForeignKey"}
GROUP_REFERENCES = {"Group", "\"sentry.Group\"", "'sentry.Group'", "sentry.Group"}

def is_group_arg(node):
    if isinstance(node, ast.Name) and node.id == "Group":
        return True
    if isinstance(node, ast.Constant) and isinstance(node.value, str):
        if node.value == "sentry.Group" or node.value.endswith(".Group"):
            return True
    if isinstance(node, ast.Attribute) and isinstance(node.value, ast.Name) and node.value.id == "settings" and node.attr == "AUTH_USER_MODEL":
        return False
    return False

def references_group(call_node):
    # positional args
    for arg in call_node.args:
        if is_group_arg(arg):
            return True
    for kw in call_node.keywords:
        if kw.arg in ("to", "related_model") and is_group_arg(kw.value):
            return True
    return False

def scan_file(path):
    try:
        tree = ast.parse(path.read_text(), filename=str(path))
    except Exception as e:
        return
    for node in ast.walk(tree):
        if not isinstance(node, ast.ClassDef):
            continue
        for body_node in node.body:
            if isinstance(body_node, ast.Assign):
                for target in body_node.targets:
                    if isinstance(target, ast.Name):
                        field_name = target.id
                    else:
                        continue
                    value = body_node.value
                    if isinstance(value, ast.Call) and isinstance(value.func, ast.Name) and value.func.id in TARGET_NAMES:
                        if references_group(value):
                            print(f"{path}:{body_node.lineno}\t{node.name}.{field_name}")
                    # Also detect group_id custom fields storing group id, but only if class is in models dirs and field name contains 'group_id'
            elif isinstance(body_node, ast.AnnAssign) and isinstance(body_node.target, ast.Name):
                field_name = body_node.target.id
                value = body_node.value
                if isinstance(value, ast.Call) and isinstance(value.func, ast.Name) and value.func.id in TARGET_NAMES:
                    if references_group(value):
                        print(f"{path}:{body_node.lineno}\t{node.name}.{field_name}")

for path in sorted(ROOT.rglob("*.py")):
    if path.name.startswith("test_") or "/tests/" in str(path):
        continue
    scan_file(path)
