import ast, os
from pathlib import Path

ROOT = Path("src/sentry")
NUMERIC_FIELD_NAMES = {"BoundedBigIntegerField", "BoundedIntegerField", "BigIntegerField", "IntegerField", "PositiveIntegerField", "models.BigIntegerField", "models.IntegerField", "models.PositiveIntegerField", "models.BigIntegerField()"}

def is_numeric_field_call(node):
    if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
        return node.func.id in {"BoundedBigIntegerField", "BoundedIntegerField", "BoundedPositiveIntegerField", "BigIntegerField", "IntegerField", "PositiveIntegerField"}
    if isinstance(node, ast.Call) and isinstance(node.func, ast.Attribute):
        if isinstance(node.func.value, ast.Name) and node.func.value.id == "models" and node.func.attr in {"BigIntegerField", "IntegerField", "PositiveIntegerField", "BigIntegerField"}:
            return True
    return False

def scan_file(path):
    try:
        tree = ast.parse(path.read_text(), filename=str(path))
    except Exception:
        return
    for node in ast.walk(tree):
        if isinstance(node, ast.ClassDef):
            for body_node in node.body:
                if isinstance(body_node, ast.Assign):
                    for target in body_node.targets:
                        if isinstance(target, ast.Name) and target.id in ("group", "group_id"):
                            if is_numeric_field_call(body_node.value):
                                print(f"{path}:{body_node.lineno}\t{node.name}.{target.id}")
                elif isinstance(body_node, ast.AnnAssign) and isinstance(body_node.target, ast.Name):
                    if body_node.target.id in ("group", "group_id") and body_node.value and is_numeric_field_call(body_node.value):
                        print(f"{path}:{body_node.lineno}\t{node.name}.{body_node.target.id}")

for path in sorted(ROOT.rglob("*.py")):
    if "/tests/" in str(path) or path.name.startswith("test_"):
        continue
    scan_file(path)
