#!/usr/bin/env python3
import json
from pathlib import Path

data = json.load(Path("/Users/luc/.local/share/opencode/tool-output/tool_f3d7de6090017G7KrQud45ruB4").open())

# Helper to compact subsystem entries: strings like "file:line | symbol | depends"

def compact_subsystem(entries):
    return [f"{e['file:line']} | {e['symbol']} | {e['depends']}" for e in entries]

def compact_change_map(entries):
    return [f"{e['file:line']} | {e['symbol']} | {e['depends']} | must_check={e['must_check']}" for e in entries]

out = {
    "step1": data["step1"],
    "step2": data["step2"],
    "step3_flat_dependents": data["step3_flat_dependents"],
    "step4_dependents_by_subsystem": {
        sub: compact_subsystem(items) for sub, items in data["step4_dependents_by_subsystem"].items()
    },
    "step5_blast_radius": {
        risk: [f"{e['file:line']} | {e['symbol']} | {e['subsystem']} | {e['notes']}" for e in items]
        for risk, items in data["step5_blast_radius"].items()
    },
    "step6_non_obvious_dependents": [
        f"{e['file:line']} | {e['symbol']} | {e['why_easy_to_miss']}"
        for e in data["step6_non_obvious_dependents"]
    ],
    "step7_change_map": {
        sub: compact_change_map(items) for sub, items in data["step7_change_map"].items()
    },
    "caveat": data["caveat"]
}

print(json.dumps(out, separators=(',', ':')))

