#!/usr/bin/env python3
import json
from pathlib import Path
from collections import defaultdict

data = json.load(Path("/Users/luc/.local/share/opencode/tool-output/tool_f3d7de6090017G7KrQud45ruB4").open())

# Build unified entry dict keyed by file:line
entries_by_ref = {}
# from step4 and step7 we can get symbol/depends/must_check
for sub, items in data["step4_dependents_by_subsystem"].items():
    for e in items:
        ref = e["file:line"]
        entries_by_ref[ref] = {
            "symbol": e["symbol"],
            "subsystem": sub,
            "depends": e["depends"],
        }
for sub, items in data["step7_change_map"].items():
    for e in items:
        ref = e["file:line"]
        entries_by_ref[ref]["must_check"] = e["must_check"]

# Add risk/notes from step5
for risk, items in data["step5_blast_radius"].items():
    for e in items:
        ref = e["file:line"]
        entries_by_ref[ref]["risk"] = risk
        entries_by_ref[ref]["notes"] = e.get("notes", "")

# Add non-obvious why
for e in data["step6_non_obvious_dependents"]:
    ref = e["file:line"]
    entries_by_ref[ref]["nonobvious_why"] = e["why_easy_to_miss"]

# Step4+7 grouped by subsystem: "file:line | symbol | depends | must_check"
step4_7 = defaultdict(list)
for ref, e in entries_by_ref.items():
    step4_7[e["subsystem"]].append(f"{ref} | {e['symbol']} | {e['depends']} | {e['must_check']}")
step4_7 = {k: step4_7[k] for k in sorted(step4_7)}

# Step5 by risk
step5 = {
    "high": [f"{ref} | {e['symbol']} | {e['subsystem']} | {e.get('notes','')}" for ref, e in entries_by_ref.items() if e.get('risk') == 'high'],
    "medium": [ref for ref, e in entries_by_ref.items() if e.get('risk') == 'medium'],
    "low": [ref for ref, e in entries_by_ref.items() if e.get('risk') == 'low'],
}

# Step6 non-obvious
step6 = [f"{ref} | {e['symbol']} | {e['nonobvious_why']}" for ref, e in entries_by_ref.items() if "nonobvious_why" in e]

out = {
    "step1": data["step1"],
    "step2": data["step2"],
    "step3_flat_dependents": data["step3_flat_dependents"],
    "step4_and_7_dependents_by_subsystem": step4_7,
    "step5_blast_radius": step5,
    "step6_non_obvious_dependents": step6,
    "caveat": data["caveat"]
}

s = json.dumps(out, separators=(',', ':'))
Path("/tmp/unified_compact_audit.json").write_text(s)
print(len(s))
